  "skill": {
    "skillId": "add-workout-to-weekly-total",
    "displayName": "Add Workout to Weekly Running Total",
    "inputs": [
      {
        "name": "workoutDistance",
        "valueType": "decimal",
        "source": "slot",
        "required": true
      },
      {
        "name": "workoutLoggedAt",
        "valueType": "datetime",
        "source": "slot",
        "required": true
      }
    ],
    "reads": [
      "workout",
      "weekly_running_mileage"
    ],
    "writes": [
      "weekly_running_mileage"
    ],
    "steps": {
      "main": [
        {
          "step": "compute",
          "expr": "format_date(workoutLoggedAt, 'week_start')",
          "as": "weekStart"
        },
        {
          "step": "read_many",
          "type": "weekly_running_mileage",
          "where": "weekStartDate == weekStart",
          "as": "existingWeek"
        },
        {
          "step": "branch",
          "condition": "count(existingWeek) > 0",
          "then": [
            {
              "step": "compute",
              "expr": "existingWeek[0].totalDistance + workoutDistance",
              "as": "newTotal"
            },
            {
              "step": "write_record",
              "type": "weekly_running_mileage",
              "id": "existingWeek[0].id",
              "updates": {
                "totalDistance": "newTotal"
              }
            }
          ],
          "else": [
            {
              "step": "write_record",
              "type": "weekly_running_mileage",
              "fields": {
                "weekStartDate": "weekStart",
                "totalDistance": "workoutDistance"
              }
            }
          ]
        }
      ]
    },
    "dangerLevel": "safe"
  },
  "safetyAssessment": {
    "level": "safe",
    "concerns": [],
    "userMessage": "This skill automatically accumulates your running distances into weekly totals—a helpful way to track progress without manual calculation."
  }
}
