  "skill": {
    "skillId": "update-weekly-running-mileage",
    "displayName": "Update Weekly Running Mileage",
    "inputs": [
      {
        "name": "workoutId",
        "valueType": "entityRef",
        "source": "slot",
        "required": true
      }
    ],
    "reads": ["workout", "weekly_running_total"],
    "writes": ["weekly_running_total"],
    "steps": {
      "main": [
        {
          "step": "read_one",
          "type": "workout",
          "id": {"var": "workoutId"},
          "output": "workout"
        },
        {
          "step": "compute",
          "expression": "now()",
          "output": "currentTime"
        },
        {
          "step": "compute",
          "expression": "format_date({var: 'currentTime'}, 'week')",
          "output": "currentWeek"
        },
        {
          "step": "read_many",
          "type": "weekly_running_total",
          "filter": {
            "field": "weekIdentifier",
            "op": "eq",
            "value": {"var": "currentWeek"}
          },
          "output": "existingTotals"
        },
        {
          "step": "branch",
          "condition": {
            "op": "gt",
            "left": {"compute": "count({var: 'existingTotals'})"},
            "right": 0
          },
          "then": [
            {
              "step": "set",
              "var": "totalRecord",
              "value": {"compute": "({var: 'existingTotals'})[0]"}
            },
            {
              "step": "compute",
              "expression": "({var: 'totalRecord'}.totalKm) + ({var: 'workout'}.distance)",
              "output": "newTotal"
            },
            {
              "step": "write_record",
              "type": "weekly_running_total",
              "id": {"var": "totalRecord.id"},
              "data": {
                "totalKm": {"var": "newTotal"}
