{
  "skill": {
    "skillId": "log-workout-and-update-weekly-mileage",
    "displayName": "Log Workout & Update Weekly Mileage",
    "inputs": [
      { "name": "distance", "valueType": "decimal", "source": "slot", "required": true },
      { "name": "loggedAt", "valueType": "datetime", "source": "slot", "required": false },
      { "name": "now", "valueType": "datetime", "source": "system", "required": true }
    ],
    "reads": ["workout", "weekly_mileage"],
    "writes": ["workout", "weekly_mileage"],
    "steps": {
      "main": [
        {
          "step": "set",
          "var": "effectiveLoggedAt",
          "value": { "if": ["loggedAt", "loggedAt", "now"] }
        },
        {
          "step": "write_record",
          "type": "workout",
          "var": "newWorkout",
          "data": {
            "distance": "distance",
            "loggedAt": "effectiveLoggedAt"
          }
        },
        {
          "step": "compute",
          "var": "weekStart",
          "fn": "add_days",
          "args": ["today()", { "compute": "*", "args": [-1, { "compute": "%", "args": [{ "compute": "days_between", "args": ["2000-01-03", "today()"] }, 7] }] }]
        },
        {
          "step": "compute",
          "var": "weekEnd",
          "fn": "add_days",
          "args": ["weekStart", 6]
        },
        {
          "step": "read_one",
          "type": "weekly_mileage",
          "var": "existingWeek",
          "filter": {
            "weekStartDate": "weekStart"
          },
          "optional": true
        },
        {
          "step": "branch",
          "condition": "existingWeek",
          "then": [
            {
              "step": "compute",
              "var": "newTotal",
              "fn": "+",
              "args": ["existingWeek.totalKm", "distance"]
            },
            {
              "step": "write_record",
              "type": "weekly_mileage",
              "recordId": "existingWeek.id",
              "data": {
                "totalKm": "newTotal"
              }
            }
          ],
          "else": [
            {
              "step": "write_record",
              "type": "weekly_mileage",
              "data": {
                "weekStartDate": "weekStart",
                "weekEndDate": "weekEnd",
                "totalKm": "distance"
              }
            }
          ]
        },
        {
          "step": "format",
          "var": "summary",
          "template": "Logged {distance} km workout. Weekly total updated."
        },
        {
          "step": "set",
          "var": "result",
          "value": "summary"
        }
      ]
    },
    "dangerLevel": "safe"
  },
