{
  "type": {
    "typeId": "weekly_running_mileage",
    "displayName": "Weekly Running Mileage",
    "displayNamePlural": "Weekly Running Mileages",
    "description": "Tracks the total running distance accumulated for a given week.",
    "examplePhrases": [
      "What's my weekly mileage?",
      "Show my running total this week",
      "How far have I run this week?"
    ],
    "attributes": [
      {
        "name": "weekStartDate",
        "label": "Week Start Date",
        "valueType": "date",
        "required": true
      },
      {
        "name": "totalDistanceKm",
        "label": "Total Distance (km)",
        "valueType": "decimal",
        "required": true
      }
    ],
    "relations": [],
    "presentation": {
      "archetype": "metric",
      "primaryField": "totalDistanceKm"
    }
  },
  "skill": {
    "skillId": "add-workout-distance-to-weekly-mileage",
    "displayName": "Add Workout Distance to Weekly Running Mileage",
    "inputs": [
      {
        "name": "workoutId",
        "valueType": "text",
        "source": "slot",
        "required": true
      },
      {
        "name": "currentDate",
        "valueType": "date",
        "source": "system",
        "required": true
      }
    ],
    "reads": ["workout", "weekly_running_mileage"],
    "writes": ["weekly_running_mileage"],
    "steps": {
      "main": [
        {
          "step": "read_one",
          "typeId": "workout",
          "id": "{{workoutId}}",
          "into": "theWorkout"
        },
        {
          "step": "compute",
          "expr": "today()",
          "into": "todayDate"
        },
        {
          "step": "compute",
          "expr": "add_days(todayDate, -(today() % 7))",
          "into": "weekStart",
          "comment": "Calculate the start of the current week (Monday-based)"
        },
        {
          "step": "read_many",
          "typeId": "weekly_running_mileage",
          "filter": {
            "weekStartDate": "{{weekStart}}"
          },
          "into": "existingWeekRecords"
        },
        {
          "step": "compute",
          "expr": "count(existingWeekRecords)",
          "into": "recordCount"
        },
        {
          "step": "branch",
          "condition": "recordCount > 0",
          "then": [
            {
              "step": "set",
              "var": "existingRecord",
              "value": "{{existingWeekRecords[0]}}"
            },
            {
              "step": "compute",
              "expr": "existingRecord.totalDistanceKm + theWorkout.distance",
              "into": "newTotal"
            },
            {
              "step": "write_record",
              "typeId": "weekly_running_mileage",
              "id": "{{existingRecord.id}}",
              "values": {
                "totalDistanceKm": "{{newTotal}}"
              }
            }
          ],
          "else": [
            {
              "step": "write_record",
              "typeId": "weekly_running_mileage",
              "values": {
                "weekStartDate": "{{weekStart}}",
                "totalDistanceKm": "{{theWorkout.distance}}"
              }
            }
          ]
        },
        {
          "step": "format",
          "template": "Added {{theWorkout.distance}} km to your weekly running mileage. Your week total is now updated.",
          "into": "resultMessage"
        }
      ]
    },
    "dangerLevel": "safe"
  },
  "safetyAssessment": {
    "level": "safe",
    "concerns": [],
    "userMessage": "This skill will update your weekly running mileage total each time you log a workout, adding the workout's distance to the current week's cumulative total."
  }
}
