{
  "skill": {
    "skillId": "log-workout-with-weekly-mileage",
    "displayName": "Log workout and update weekly mileage",
    "inputs": [
      {"name": "distance", "valueType": "decimal", "source": "slot", "required": true},
      {"name": "loggedAt", "valueType": "datetime", "source": "system", "required": true}
    ],
    "reads": ["workout"],
    "writes": ["workout"],
    "steps": {
      "main": [
        {
          "op": "write_record",
          "type": "workout",
          "fields": {
            "distance": "$distance",
            "loggedAt": "$loggedAt"
          },
          "as": "newWorkout"
        },
        {
          "op": "compute",
          "expr": "add_days(today(), -7)",
          "as": "weekStart"
        },
        {
          "op": "read_many",
          "type": "workout",
          "where": {"loggedAt": {"gte": "$weekStart"}},
          "as": "recentWorkouts"
        },
        {
          "op": "compute",
          "expr": "sum(recentWorkouts.distance)",
          "as": "weeklyMileage"
        },
        {
          "op": "format",
          "template": "Workout logged: {{distance}} km. Weekly running mileage (last 7 days): {{weeklyMileage}} km.",
          "vars": {"distance": "$distance", "weeklyMileage": "$weeklyMileage"},
          "as": "message"
        }
      ]
    },
    "dangerLevel": "safe"
  },
  "safetyAssessment": {
    "level": "safe",
    "concerns": [],
    "userMessage": "This skill logs a workout and computes your rolling 7-day running mileage from stored workouts. Note: rather than storing a separate weekly total (which can drift), it derives the total on demand from your workout records."
  }
}

{
  "skill": {
    "skillId": "weekly-running-mileage",
    "displayName": "Weekly Running Mileage Total",
    "inputs": [],
    "reads": ["workout"],
    "writes": [],
    "steps": {
      "main": [
        {
          "op": "compute",
          "as": "weekStart",
          "expr": "add_days(today(), 0 - days_between(today(), today()) )"
        },
        {
          "op": "compute",
          "as": "sevenDaysAgo",
          "expr": "add_days(today(), -7)"
        },
        {
          "op": "read_many",
          "type": "workout",
          "as": "recentWorkouts",
          "where": "loggedAt >= sevenDaysAgo"
        },
        {
          "op": "compute",
          "as": "totalDistance",
          "expr": "sum(recentWorkouts.distance)"
        },
        {
          "op": "format",
          "as": "message",
          "expr": "concat('Weekly running mileage: ', totalDistance, ' km')"
        }
      ]
    },
    "dangerLevel": "safe"
  },
  "safetyAssessment": {
    "level": "safe",
    "concerns": [],
    "userMessage": "This capability sums the distance of all workouts logged in the past 7 days into a running weekly total. Since your interpreter can't run on each log automatically, this is set up as an on-demand skill you can invoke anytime to see your current weekly mileage."
  }
}
